export function hasPermission(role, requiredPermission) {
    if (!role)
        return false;
    const permissions = ROLE_PERMISSIONS[role] ?? [];
    return (permissions.includes("*") ||
        permissions.includes(requiredPermission));
}
export function recordAuthFailure(req, permission, statusCode) {
    return writeAuditLog({
        action: "auth.rbac.denied",
        resourceType: "authorization",
        resourceId: req.user?.id,
        context: {
            permission,
            statusCode,
            path: req.originalUrl,
            method: req.method,
            role: req.user?.role,
        },
        actor: req.user,
        request: req,
    });
}
export function rbacMiddleware(requiredPermission) {
    return async (req, res, next) => {
        if (!req.user) {
            return res.status(401).json({ error: "Unauthorized" });
        }
        if (hasPermission(req.user.role, requiredPermission)) {
            return next();
        }
        await recordAuthFailure(req, requiredPermission, 403);
        return res.status(403).json({
            error: "Forbidden: insufficient permissions",
            permission: requiredPermission,
        });
    };
}
export function requirePermission(permission) {
    return async (req, res, next) => {
        if (!req.user) {
            return res.status(401).json({ error: "Unauthorized" });
        }
        if (hasPermission(req.user.role, permission)) {
            return next();
        }
        await recordAuthFailure(req, permission, 403);
        return res.status(403).json({
            error: "Forbidden: insufficient permissions",
            permission,
        });
    };
}
export function requireRole(allowedRoles) {
    return async (req, res, next) => {
        if (!req.user) {
            return res.status(401).json({ error: "Unauthorized" });
        }
        if (allowedRoles.includes(req.user.role)) {
            return next();
        }
        await recordAuthFailure(req, `role:${req.user.role}`, 403);
        return res.status(403).json({
            error: "Forbidden: insufficient permissions",
        });
    };
}
